fn binary_search(v: i64, n: i64, target: i64) -> i64 =
    {
        let mut lo: i64 = 0;
        let mut hi: i64 = n - 1;
        let mut result: i64 = 0 - 1;
        while lo <= hi {
            let mid: i64 = lo + (hi - lo) / 2;
            let val: i64 = vec_get(v, mid);
            if val == target {
                result = mid;
                lo = hi + 1
            } else if val < target {
                lo = mid + 1
            } else {
                hi = mid - 1
            }
        };
        result
    };

